SELECT [Sales Line].[Document Type], [Sales Line].Type, [Sales Header].No_ AS OrderNo, [Sales Line].[Line No_], [Sales Line].No_, Val([Quantity]) AS QuantitySold, [Sales Line].[Unit of Measure], [Sales Line].[Constant Variable Code], [Sales Line].[Assortment Code], Val([No_ of Pairs]) AS PairsSold, Salesperson_Purchaser.Name AS Salesperson, [Sales Line].[Delete Reason], [Sales Line].[Customer Price Group], [Sales Line].[Average Unit Price], [Sales Header].[Salesperson Code], [Sales Line].[Av_ Net Unit Price], [Sales Line].[Currency Code], Val([Line Amount])-Val([Inv_ Discount Amount]) AS ValueSold, Val([Average Unit Price]) AS GrossUnitPrice, Val([average unit price])*Val([no_ of pairs]) AS GrossSalesValue, [GrossSalesValue]-[ValueSold] AS DiscountValue, Val(Nz([Area Manager Commission _]))*[valuesold]/10 AS AreaManagerCommissionValue, Val(Nz([Salesperson Commission _]))*[valuesold]/100 AS SalesPersonCommissionValue, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity shipped])/Val([Sales Line.quantity])*(Val([sales line.Line Amount])-Val([sales line.Inv_ Discount Amount])),0) AS ValueShipped, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity shipped])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0) AS PairsShipped, Val([Sales Line.Quantity Shipped]) AS QuantityShipped, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*(Val([sales line.Line Amount])-Val([sales line.Inv_ Discount Amount])),0) AS ValueInvoiced, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0) AS Pairsinvoiced, Val([Sales Line.Quantity invoiced]) AS QuantityInvoiced
FROM (([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group])
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=20) AND (([Sales Line].[Delete Reason])=""))
ORDER BY [Sales Header].No_;

